// Verify webhook secret if configured
const secret = $env.N8N_WEBHOOK_SECRET;
if (secret) {
  const receivedSecret = $input.headers['x-webhook-secret'];
  if (receivedSecret !== secret) {
    return [{ json: { error: 'Unauthorized' } }];
  }
}

// Extract body data
const body = $input.body;

// Convert arrays to comma-separated strings
const formatArray = (arr) => {
  if (!arr || !Array.isArray(arr)) return '';
  return arr.join(', ');
};

// High intent qualification logic
const teamSize = body.teamSize;
const adminHours = body.weeklyAdminHours;
let highIntentTag = false;

// Parse team size
const teamSizeMap = {
  'Just me': 1,
  '2–5': 3,
  '6–20': 10,
  '20+': 25
};

// Parse admin hours (use middle of range)
const adminHoursMap = {
  'Under 2 hours': 1,
  '2–5 hours': 3.5,
  '5–10 hours': 7.5,
  '10–15 hours': 12.5,
  '15+ hours (I feel this)': 17
};

const teamSizeNum = teamSizeMap[teamSize] || 1;
const adminHoursNum = adminHoursMap[adminHours] || 0;

if (teamSizeNum >= 6 && adminHoursNum >= 10) {
  highIntentTag = true;
}

return [{
  json: {
    ...body,
    repeatedTasks: formatArray(body.repeatedTasks),
    tools: formatArray(body.tools),
    highIntentTag,
    teamSizeNum,
    adminHoursNum
  }
}];

